SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW view_tel_req_dep (seq_no, membership_no, deposit_account_no, deposit_balance, deposit_type_code, loan_type_coll, remark) AS select seq_no , membership_no ,deposit_account_no , deposit_balance , deposit_type_code , loan_type_coll , remark
FROM
( select 1 as seq_no 
,sc_dep_m_creditor.membership_no
,sc_dep_m_creditor.deposit_account_no
,sc_dep_m_creditor.deposit_balance
,sc_dep_m_rule.deposit_type_code||' - '||sc_dep_m_rule.deposit_name  as deposit_type_code
,CASE WHEN  sc_dep_m_rule.deposit_type_code ='60' THEN  'กองทุนช่วยเหลือผู้ค้ำ'                            WHEN  sc_dep_m_rule.deposit_type_code ='61' THEN  'ค้ำประกันแทนหุ้น'                             ELSE '' END  as loan_type_coll
, sc_dep_m_creditor.remark
from sc_dep_m_creditor
,sc_dep_m_rule
where 1=1
and sc_dep_m_creditor.close_status = '0'
--and sc_dep_m_creditor.deposit_type_code in ('60','61' ,'00' , '01') 
and sc_dep_m_rule.deposit_type_code = sc_dep_m_creditor.deposit_type_code
and sc_dep_m_rule.deposit_group_code = '01'
                

union all


select 2 as seq_no 
,sc_mem_m_membership_registered.crem_memno AS membership_no
,sc_dep_m_creditor.deposit_account_no
,sc_dep_m_creditor.deposit_balance
, (select sc_dep_m_rule.deposit_type_code||' - '||sc_dep_m_rule.deposit_name from sc_dep_m_rule@db_crem where sc_dep_m_rule.deposit_type_code = sc_dep_m_creditor.deposit_type_code ) as deposit_type_code
,'เงินกู้พัฒนา' as loan_type_coll
, 'รอเรียกเก็บ '||to_char(4000 - sc_dep_m_creditor.deposit_balance ,'999,999.99') || ' บาท' as remark
from sc_mem_m_membership_registered@db_crem
,sc_dep_m_creditor@db_crem    
where 1=1
and sc_dep_m_creditor.close_status = '0'
and sc_mem_m_membership_registered.member_status_code = '0' 
and sc_mem_m_membership_registered.membership_no = sc_dep_m_creditor.membership_no
and sc_dep_m_creditor.deposit_type_code in ('01')
--Niorn 2023-07-13 
and CASE WHEN  pka.isCoop('TGE')  				='1' THEN  1				  ELSE 0 END   = 1    

) tb 
where 1=1
/*WHERE */

--AND membership_no = '043069'
order by seq_no, deposit_account_no;

